// ✅ Preprocess Node (Model-Ready Payload)
// Output schema matches FastAPI /predict_risk exactly
// Handles unusual/impossible values via validation + clamping + fallbacks

function num(x) {
  if (x === null || x === undefined || x === "") return null;
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

function int01(x) {
  // normalize boolean / yes/no / 0/1 / "true"/"false"
  if (x === true) return 1;
  if (x === false) return 0;
  if (x === null || x === undefined || x === "") return 0;

  const s = String(x).trim().toLowerCase();
  if (["1", "yes", "y", "true"].includes(s)) return 1;
  if (["0", "no", "n", "false"].includes(s)) return 0;

  const n = Number(s);
  return n === 1 ? 1 : 0;
}

function text(x) {
  if (x === null || x === undefined) return "";
  return String(x).trim();
}

function clamp(n, lo, hi) {
  if (n === null) return null;
  return Math.max(lo, Math.min(hi, n));
}

function safeDipstick(x) {
  // Our model expects proteinuria_dipstick numeric 0–3
  // Accepts: 0, 0.5, 1, 2, 3, "trace", "1+", "2+", "3+", "+"
  if (x === null || x === undefined || x === "") return null;

  // numeric already
  const n = Number(x);
  if (Number.isFinite(n)) {
    // clamp strictly to 0..3
    return clamp(n, 0, 3);
  }

  // string mapping
  const s = String(x).trim().toLowerCase();
  if (s === "negative" || s === "neg" || s === "0") return 0;
  if (s === "trace") return 0.5;
  if (s === "+" || s === "1+") return 1;
  if (s === "2+") return 2;
  if (s === "3+") return 3;

  // unknown string
  return null;
}

// --------------------------------------
// ✅ INPUT (raw from test case OR multi-source merge)
// --------------------------------------
const raw = $input.first().json;

// --------------------------------------
// ✅ Output EXACT schema expected by FastAPI /predict_risk
// (matching PatientData in backend)
// --------------------------------------
const out = {
  patient_id: text(raw.patient_id || "UNKNOWN"),

  timestamp: raw.timestamp ? String(raw.timestamp) : new Date().toISOString(),

  gestational_age_weeks: clamp(num(raw.gestational_age_weeks), 5, 45),
  maternal_age: clamp(num(raw.maternal_age), 14, 55),
  pre_pregnancy_bmi: clamp(num(raw.pre_pregnancy_bmi), 10, 70),
  gdm_diagnosed: int01(raw.gdm_diagnosed),

  // ✅ Preeclampsia vitals
  systolic_bp: clamp(num(raw.systolic_bp), 70, 220),
  diastolic_bp: clamp(num(raw.diastolic_bp), 40, 140),

  severe_headache: int01(raw.severe_headache),
  vision_changes: int01(raw.vision_changes),
  upper_abdominal_pain: int01(raw.upper_abdominal_pain),
  swelling_face_hands: int01(raw.swelling_face_hands),

  proteinuria_dipstick: safeDipstick(raw.proteinuria_dipstick),

  // ✅ Macrosomia/GDM vitals + behavior
  fasting_glucose: clamp(num(raw.fasting_glucose), 40, 300),
  postprandial_1hr_glucose: clamp(num(raw.postprandial_1hr_glucose), 40, 350),

  post_meal_walk_minutes: clamp(num(raw.post_meal_walk_minutes), 0, 180),
  sleep_hours: clamp(num(raw.sleep_hours), 0, 16),

  // ✅ periodic/manual
  weight_kg: clamp(num(raw.weight_kg), 30, 250),
  hba1c: clamp(num(raw.hba1c), 3.0, 12.0),

  // ✅ text
  food_log_text: text(raw.food_log_text)
};

// --------------------------------------
// ✅ Impossible-value correction rules (strong demo point)
// --------------------------------------

// 1) If diastolic > systolic (impossible) -> swap
if (out.systolic_bp !== null && out.diastolic_bp !== null) {
  if (out.diastolic_bp > out.systolic_bp) {
    const temp = out.systolic_bp;
    out.systolic_bp = out.diastolic_bp;
    out.diastolic_bp = temp;
  }
}

// 2) Gestational age unrealistic -> set null (not clamp)
// because if someone enters 120 weeks it's garbage
if (out.gestational_age_weeks !== null && (out.gestational_age_weeks < 10 || out.gestational_age_weeks > 45)) {
  out.gestational_age_weeks = null;
}

// 3) Negative glucose or sleep should be null
if (out.fasting_glucose !== null && out.fasting_glucose < 0) out.fasting_glucose = null;
if (out.postprandial_1hr_glucose !== null && out.postprandial_1hr_glucose < 0) out.postprandial_1hr_glucose = null;
if (out.sleep_hours !== null && out.sleep_hours < 0) out.sleep_hours = null;

// 4) If postprandial is less than fasting by huge margin, keep but flag using metadata (optional)
const flags = [];

if (!out.patient_id || out.patient_id === "UNKNOWN") flags.push("missing_patient_id");
if (out.systolic_bp === null || out.diastolic_bp === null) flags.push("missing_bp");
if (out.fasting_glucose === null || out.postprandial_1hr_glucose === null) flags.push("missing_glucose");
if (out.proteinuria_dipstick === null) flags.push("missing_proteinuria");
