  else if (out.postprandial_1hr_glucose >= 140) flags.push("post_meal_glucose_above_target_flag");
}

if (out.sleep_hours !== null && out.sleep_hours < 4) flags.push("low_sleep_flag");
if (out.post_meal_walk_minutes !== null && out.post_meal_walk_minutes === 0) flags.push("no_post_meal_walk_flag");

// --------------------------------------
// ✅ Keep output strictly model-ready,
// but attach extra metadata for n8n routing/logging
// --------------------------------------
return {
  json: {
    ...out,

  }
};

