// Build_Emergency_Payload
// Input should already contain merged vitals + model output + agent_output fields

const j = $json;

// ensure base fields exist
const patient_id = j.patient_id || "UNKNOWN";

// Determine emergency reason (PE / MAC / BOTH)
let emergency_reason = "URGENT REVIEW";
if (j.preeclampsia_risk_tier === "high" && j.macrosomia_risk_tier === "high") {
  emergency_reason = "HIGH PREECLAMPSIA + HIGH MACROSOMIA RISK";
} else if (j.preeclampsia_risk_tier === "high") {
