const chunkSize = 500;
const overlap = 50;

const text = $input.first().json.text;

let chunks = [];
let start = 0;

while (start < text.length) {
  const end = start + chunkSize;
  chunks.push({
    json: {
      chunk: text.slice(start, end)
    }
  });
  start += chunkSize - overlap;
}

return chunks;

