  let score = 0;

  for (const word of words) {
    if (text.includes(word)) {
      score++;
    }
  }

  return { chunk, score };
});

scored.sort((a, b) => b.score - a.score);

const topChunks = scored.slice(0, 5).map(c => c.chunk);

return [
