--------------------------------------------------- */

const required_fields = [
  "summary",
  "preeclampsia_assessment",
  "macrosomia_assessment",
  "recommended_action",
  "patient_message",
  "doctor_message",
  "confidence"
];

for (const field of required_fields) {
  if (!d[field]) {
    safety_passed = false;
    issues.push(`Missing required field: ${field}`);
  }
}

/* ---------------------------------------------------
2️⃣ VALID ACTION CHECK
--------------------------------------------------- */

const allowed_actions = [
  "LOG_ONLY",
  "COACH_PATIENT",
  "ALERT_DOCTOR",
  "EMERGENCY"
];

if (!allowed_actions.includes(d.recommended_action)) {
  safety_passed = false;
  issues.push("Invalid recommended_action value.");
}

/* ---------------------------------------------------
3️⃣ SEVERE HYPERTENSION SAFETY RULE
BP ≥160 / 110 must escalate
--------------------------------------------------- */

if (d.systolic_bp >= 160 || d.diastolic_bp >= 110) {
  if (d.recommended_action !== "EMERGENCY") {
    safety_passed = false;
    issues.push(
      "Severe hypertension detected but AI did not escalate to EMERGENCY."
    );
  }
}

/* ---------------------------------------------------
4️⃣ HYPERTENSION RULE
BP ≥140 / 90 cannot be LOG_ONLY
--------------------------------------------------- */

if (d.systolic_bp >= 140 || d.diastolic_bp >= 90) {
  if (d.recommended_action === "LOG_ONLY") {
    safety_passed = false;
    issues.push(
      "Hypertension detected but AI recommended LOG_ONLY."
    );
  }
}

/* ---------------------------------------------------
5️⃣ PROTEINURIA + BP CHECK (possible preeclampsia)
--------------------------------------------------- */

if (
  d.proteinuria_dipstick >= 2 &&
  (d.systolic_bp >= 140 || d.diastolic_bp >= 90)
) {
  if (d.recommended_action === "LOG_ONLY") {
    safety_passed = false;
    issues.push(
      "Possible preeclampsia signs but AI recommended LOG_ONLY."
    );
  }
}

/* ---------------------------------------------------
6️⃣ AI vs ML MODEL DISAGREEMENT CHECK
--------------------------------------------------- */

const peModelTier = root.preeclampsia_risk_tier;
const macModelTier = root.macrosomia_risk_tier;
const aiAction = d.recommended_action;

// Preeclampsia disagreement
if (peModelTier === "high" && aiAction !== "EMERGENCY") {
  safety_passed = false;
  issues.push(
    "Model indicates HIGH preeclampsia risk but AI did not escalate."
  );
}

if (peModelTier === "medium" && aiAction === "LOG_ONLY") {
  safety_passed = false;
  issues.push(
    "Model indicates MEDIUM preeclampsia risk but AI downgraded to LOG_ONLY."
  );
}

// Macrosomia disagreement
if (macModelTier === "high" && aiAction === "LOG_ONLY") {
  safety_passed = false;
  issues.push(
    "Model indicates HIGH macrosomia risk but AI recommended LOG_ONLY."
  );
}

/* ---------------------------------------------------
7️⃣ CONFIDENCE SANITY CHECK
--------------------------------------------------- */

if (typeof d.confidence !== "number") {
  safety_passed = false;
  issues.push("Confidence must be numeric.");
}

if (d.confidence < 0.4) {
  issues.push("Low AI confidence output.");
}

/* ---------------------------------------------------
8️⃣ OUTPUT
--------------------------------------------------- */

return [
  {
    json: {
      ...root,
      safety_passed,
      safety_issues: issues
    }
  }
];

const data = $json;

// initialize retry_count if it doesn't exist
if (!data.retry_count) {
  data.retry_count = 0;
}

// increment retry
data.retry_count += 1;

return [{ json: data }];

