const data = { ...$json };

// Access model paths
const pe_path = data.agent_output?.model_loaded?.preeclampsia_dir;
const mac_path = data.agent_output?.model_loaded?.macrosomia_dir;


// Function to extract version safely (works for both / and \)
function extractVersion(path) {
  if (!path) return "";
  return path.split(/[/\\]/).pop(); // handles Windows + Linux paths
}


// Extract versions
const pe_version = extractVersion(pe_path);
const mac_version = extractVersion(mac_path);


// Add new fields (without modifying anything else)
data["Preeclampsia Model Version"] = pe_version;
data["Macrosomia Model Version"] = mac_version;


// Return full unchanged JSON + new fields
return [
  {
    json: data
  }
];

