  {
    json: {
      patient_id: query.patient_id || body.patient_id,
      action: query.action || body.action,

      Select: body.Select || query.Select || body.select || query.select || "",
      Feedback: body.Feedback || query.Feedback || body.feedback || query.feedback || ""
    }
  }
];

