function mapDoctorLabel(predicted, doctorAction) {

  if (!predicted) return "";

  if (doctorAction === "False Alert") {
    if (predicted === "high") return "medium";
    if (predicted === "medium") return "low";
    return "low";
  }

  if (doctorAction === "Escalate") return "high";

  if (doctorAction === "Acknowledge") return predicted;

  return predicted;
}

